NEW_SAVE_MAP_BLOCK = """    def save_map(self, name: str) -> dict:\n        try:\n            safe_name = self._sanitize_asset_name(name, 'Invalid map name')\n        except RuntimeError as exc:\n            return {'ok': False, 'error': str(exc)}\n\n        base_path = self.map3d_dir / safe_name\n        pcd_path = base_path.with_suffix('.pcd')\n        ply_path = base_path.with_suffix('.ply')\n        cached_payload = self.ros_state.latest_pgo_payload()\n        service_output = ''\n\n        try:\n            self.map3d_dir.mkdir(parents=True, exist_ok=True)\n            if self._pgo_running():\n                self.ros_state.configure_pgo_save(str(base_path), 0.10, timeout=20.0)\n                service_output = self.ros_state.trigger_pgo_save(timeout=240.0)\n            elif cached_payload is None:\n                return {'ok': False, 'error': 'PGO is not running and no cached global map is available'}\n        except Exception as exc:\n            if cached_payload is None:\n                return {'ok': False, 'error': str(exc)}\n            service_output = str(exc)\n\n        fallback_details = None\n        if cached_payload is not None and (not pcd_path.exists() or not ply_path.exists()):\n            try:\n                fallback_details = self._save_cached_point_cloud(base_path, cached_payload)\n            except Exception:\n                if not pcd_path.exists() and not ply_path.exists():\n                    return {'ok': False, 'error': service_output or 'Failed to save PGO 3D map'}\n\n        response = {\n            'ok': True,\n            'message': f'Saved PGO 3D map to {pcd_path.name}',\n            'map': {\n                'name': safe_name,\n                'pcd': str(pcd_path) if pcd_path.exists() else '',\n                'ply': str(ply_path) if ply_path.exists() else '',\n            },\n        }\n        if ply_path.exists():\n            response['message'] += f' and {ply_path.name}'\n        if fallback_details is not None:\n            response['message'] += f' (fallback cached sample: {fallback_details[\"sampled_points\"]} pts)'\n        response['details'] = service_output\n\n        map2d_result = self.save_map_2d(safe_name, 'slam')\n        response['map2d'] = map2d_result.get('map', {})\n        response['map2d_source'] = 'live_slam_toolbox'\n        response['map2d_details'] = map2d_result.get('details', '')\n        if not map2d_result.get('ok'):\n            response['ok'] = False\n            response['error'] = map2d_result.get('error') or 'Failed to save slam_toolbox 2D map'\n            response['message'] += f'; slam_toolbox 2D save failed: {response[\"error\"]}'\n            return response\n\n        nav_yaml_path = Path(map2d_result['map']['yaml'])\n        localizer_script = Path(os.environ.get('NJRH_LOCALIZER_PREPARE_SCRIPT', str(ROOT_DIR / 'scripts' / 'prepare_localizer_map.py')))\n        localizer_output_dir = Path(os.environ.get('NJRH_LOCALIZER_OUTPUT_DIR', str(nav_yaml_path.parent)))\n        localizer_yaml_path = localizer_output_dir / f'{nav_yaml_path.stem}.localizer.yaml'\n        localizer_png_path = localizer_output_dir / f'{nav_yaml_path.stem}.localizer.png'\n        if not localizer_script.exists():\n            response['ok'] = False\n            response['error'] = f'Localizer asset helper not found: {localizer_script}'\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            return response\n\n        localizer_command = [\n            'python3',\n            str(localizer_script),\n            '--nav-yaml',\n            str(nav_yaml_path),\n            '--output-dir',\n            str(localizer_output_dir),\n        ]\n        localizer_output = ''\n        try:\n            completed = subprocess.run(\n                localizer_command,\n                cwd=str(ROOT_DIR),\n                env=os.environ.copy(),\n                capture_output=True,\n                text=True,\n                timeout=120.0,\n                check=False,\n            )\n            localizer_output = (completed.stdout or completed.stderr or '').strip()\n            if completed.returncode != 0:\n                response['ok'] = False\n                response['error'] = localizer_output or 'Failed to generate Isaac localizer assets'\n                response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n                return response\n            output_lines = [line.strip() for line in (completed.stdout or '').splitlines() if line.strip()]\n            if output_lines:\n                localizer_yaml_path = Path(output_lines[-1])\n                localizer_png_path = localizer_yaml_path.parent / f'{nav_yaml_path.stem}.localizer.png'\n        except Exception as exc:\n            response['ok'] = False\n            response['error'] = str(exc)\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            return response\n\n        if not localizer_yaml_path.exists() or not localizer_png_path.exists():\n            response['ok'] = False\n            response['error'] = 'Isaac localizer assets were not generated as expected'\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            response['localizer_details'] = localizer_output\n            return response\n\n        response['localizer_map'] = {\n            'yaml': str(localizer_yaml_path),\n            'image': str(localizer_png_path),\n        }\n        response['message'] += f\"; slam_toolbox 2D map saved as {nav_yaml_path.name} and {Path(map2d_result['map']['image']).name}; Isaac localizer assets saved as {localizer_yaml_path.name} and {localizer_png_path.name}\"\n        response['localizer_details'] = localizer_output\n        return response\n"""


