NEW_SAVE_MAP_2D_BLOCK = """    def save_map_2d(self, name: str, source: str = 'slam') -> dict:\n        try:\n            safe_name = self._sanitize_asset_name(name, 'Invalid 2D map name')\n        except RuntimeError as exc:\n            return {'ok': False, 'error': str(exc)}\n        requested_source = str(source or 'slam').strip().lower()\n        if requested_source not in ('slam', 'projected', 'auto'):\n            requested_source = 'slam'\n        feature_names: List[str] = []\n        if requested_source in ('slam', 'auto'):\n            feature_names.append('slam_map_live')\n        if requested_source in ('projected', 'auto'):\n            feature_names.append('projected_map_live')\n\n        with self._temporary_view_features(feature_names, source='internal:save_map_2d'):\n            def _payload_ready() -> bool:\n                payload = self.latest_live_map_full_payload(prefer=requested_source)\n                if payload is None:\n                    return False\n                if requested_source == 'slam':\n                    return str(payload.get('frame_id', '')).strip() == 'map'\n                if requested_source == 'projected':\n                    return True\n                return True\n\n            self._wait_until(\n                _payload_ready,\n                timeout=12.0,\n                description='live slam_toolbox occupancy grid' if requested_source == 'slam' else 'live occupancy grid',\n            )\n            payload = self.latest_live_map_full_payload(prefer=requested_source)\n        if payload is None:\n            if requested_source == 'slam':\n                return {'ok': False, 'error': 'No live /map occupancy grid received yet'}\n            if requested_source == 'projected':\n                return {'ok': False, 'error': 'No live /projected_map occupancy grid received yet'}\n            return {'ok': False, 'error': 'No live occupancy grid received yet'}\n        base_path = self.map2d_dir / safe_name\n        yaml_path = base_path.with_suffix('.yaml')\n        pgm_path = base_path.with_suffix('.pgm')\n        png_path = base_path.with_suffix('.png')\n        try:\n            self.map2d_dir.mkdir(parents=True, exist_ok=True)\n            saved = self._save_occupancy_snapshot(base_path, payload)\n        except Exception as exc:\n            return {'ok': False, 'error': str(exc)}\n        if not yaml_path.exists():\n            return {'ok': False, 'error': f'2D map save did not create {yaml_path.name}'}\n\n        response = {\n            'ok': True,\n            'message': f'Saved 2D map from {payload.get(\"source\", \"occupancy_grid\")} to {yaml_path.name}',\n            'map': {\n                'name': safe_name,\n                'yaml': saved['yaml'],\n                'image': saved['image'],\n            },\n            'details': payload.get('source', 'occupancy_grid'),\n            'source': payload.get('source', 'occupancy_grid'),\n        }\n        if png_path.exists():\n            response['message'] += f' and {png_path.name}'\n        elif pgm_path.exists():\n            response['message'] += f' and {pgm_path.name}'\n\n        localizer_script = Path(os.environ.get('NJRH_LOCALIZER_PREPARE_SCRIPT', str(ROOT_DIR / 'scripts' / 'prepare_localizer_map.py')))\n        localizer_output_dir = Path(os.environ.get('NJRH_LOCALIZER_OUTPUT_DIR', str(yaml_path.parent)))\n        localizer_yaml_path = localizer_output_dir / f'{yaml_path.stem}.localizer.yaml'\n        localizer_png_path = localizer_output_dir / f'{yaml_path.stem}.localizer.png'\n        if not localizer_script.exists():\n            response['ok'] = False\n            response['error'] = f'Localizer asset helper not found: {localizer_script}'\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            return response\n\n        localizer_command = [\n            'python3',\n            str(localizer_script),\n            '--nav-yaml',\n            str(yaml_path),\n            '--output-dir',\n            str(localizer_output_dir),\n        ]\n        localizer_output = ''\n        try:\n            completed = subprocess.run(\n                localizer_command,\n                cwd=str(ROOT_DIR),\n                env=os.environ.copy(),\n                capture_output=True,\n                text=True,\n                timeout=120.0,\n                check=False,\n            )\n            localizer_output = (completed.stdout or completed.stderr or '').strip()\n            if completed.returncode != 0:\n                response['ok'] = False\n                response['error'] = localizer_output or 'Failed to generate Isaac localizer assets'\n                response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n                return response\n            output_lines = [line.strip() for line in (completed.stdout or '').splitlines() if line.strip()]\n            if output_lines:\n                localizer_yaml_path = Path(output_lines[-1])\n                localizer_png_path = localizer_yaml_path.parent / f'{yaml_path.stem}.localizer.png'\n        except Exception as exc:\n            response['ok'] = False\n            response['error'] = str(exc)\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            return response\n\n        if not localizer_yaml_path.exists() or not localizer_png_path.exists():\n            response['ok'] = False\n            response['error'] = 'Isaac localizer assets were not generated as expected'\n            response['message'] += f'; localizer asset generation failed: {response[\"error\"]}'\n            response['localizer_details'] = localizer_output\n            return response\n\n        response['localizer_map'] = {\n            'yaml': str(localizer_yaml_path),\n            'image': str(localizer_png_path),\n        }\n        response['message'] += f\"; Isaac localizer assets saved as {localizer_yaml_path.name} and {localizer_png_path.name}\"\n        response['localizer_details'] = localizer_output\n        return response\n"""


