NEW_STORE_OCCUPANCY_GRID_BLOCK = """def _store_occupancy_grid(self, msg: OccupancyGrid, target: str, source: str) -> None:\n        data = list(msg.data)\n        if not data or msg.info.width <= 0 or msg.info.height <= 0:\n            return\n        max_cells = 1440000 if target == 'projected' else 240000\n        stride = max(1, int(math.ceil(math.sqrt(len(data) / max_cells))))\n        sample_width = max(1, int(math.ceil(msg.info.width / stride)))\n        sample_height = max(1, int(math.ceil(msg.info.height / stride)))\n        sampled: List[int] = []\n        for row in range(0, msg.info.height, stride):\n            row_offset = row * msg.info.width\n            for col in range(0, msg.info.width, stride):\n                sampled.append(int(data[row_offset + col]))\n        origin = msg.info.origin.position\n        payload = {\n            'source': source,\n            'frame_id': msg.header.frame_id or 'map',\n            'stamp': {'sec': int(msg.header.stamp.sec), 'nanosec': int(msg.header.stamp.nanosec)},\n            'width': int(msg.info.width),\n            'height': int(msg.info.height),\n            'resolution': float(msg.info.resolution),\n            'origin': {\n                'x': float(origin.x),\n                'y': float(origin.y),\n                'z': float(origin.z),\n            },\n            'sample_stride': int(stride),\n            'sample_width': int(sample_width),\n            'sample_height': int(sample_height),\n            'data': sampled,\n            'updated_at': time.time(),\n        }\n        full_payload = {\n            'source': source,\n            'frame_id': msg.header.frame_id or 'map',\n            'stamp': {'sec': int(msg.header.stamp.sec), 'nanosec': int(msg.header.stamp.nanosec)},\n            'width': int(msg.info.width),\n            'height': int(msg.info.height),\n            'resolution': float(msg.info.resolution),\n            'origin': {\n                'x': float(origin.x),\n                'y': float(origin.y),\n                'z': float(origin.z),\n            },\n            'data': data,\n            'updated_at': payload['updated_at'],\n        }\n        with self._lock:\n            if target == 'projected':\n                self._projected_map_grid = payload\n                self._projected_map_grid_full = full_payload\n            elif target == 'local_costmap':\n                self._local_costmap_grid = payload\n                self._local_costmap_grid_full = full_payload\n            else:\n                self._map_grid = payload\n                self._map_grid_full = full_payload\n\n    """


NEW_DRAW_OCCUPANCY_IMAGE_BLOCK = """function drawOccupancyImage(targetCanvas, targetCtx, mapPayload, emptyMessage) {\n      targetCtx.clearRect(0, 0, targetCanvas.width, targetCanvas.height);\n      targetCtx.fillStyle = '#f7fbff';\n      targetCtx.fillRect(0, 0, targetCanvas.width, targetCanvas.height);\n      targetCtx.save();\n      targetCtx.strokeStyle = 'rgba(150, 184, 218, 0.16)';\n      targetCtx.lineWidth = 1;\n      const gridSpacing = 12;\n      for (let x = 0; x <= targetCanvas.width; x += gridSpacing) { targetCtx.beginPath(); targetCtx.moveTo(x + 0.5, 0); targetCtx.lineTo(x + 0.5, targetCanvas.height); targetCtx.stroke(); }\n      for (let y = 0; y <= targetCanvas.height; y += gridSpacing) { targetCtx.beginPath(); targetCtx.moveTo(0, y + 0.5); targetCtx.lineTo(targetCanvas.width, y + 0.5); targetCtx.stroke(); }\n      targetCtx.restore();\n      if (!mapPayload || !Array.isArray(mapPayload.data) || !mapPayload.data.length) {\n        targetCtx.save();\n        targetCtx.fillStyle = '#6f88a2';\n        targetCtx.font = '16px sans-serif';\n        targetCtx.textAlign = 'center';\n        targetCtx.fillText(emptyMessage, targetCanvas.width / 2, targetCanvas.height / 2);\n        targetCtx.restore();\n        return null;\n      }\n      const width = mapPayload.sample_width;\n      const height = mapPayload.sample_height;\n      const data = mapPayload.data;\n      let minSampleX = width;\n      let minSampleY = height;\n      let maxSampleX = -1;\n      let maxSampleY = -1;\n      for (let i = 0; i < data.length; i += 1) {\n        const value = Number(data[i]);\n        if (!Number.isFinite(value) || value < 0) continue;\n        const sampleX = i % width;\n        const sampleY = Math.floor(i / width);\n        if (sampleX < minSampleX) minSampleX = sampleX;\n        if (sampleY < minSampleY) minSampleY = sampleY;\n        if (sampleX > maxSampleX) maxSampleX = sampleX;\n        if (sampleY > maxSampleY) maxSampleY = sampleY;\n      }\n      if (maxSampleX < 0 || maxSampleY < 0) {\n        minSampleX = 0;\n        minSampleY = 0;\n        maxSampleX = width - 1;\n        maxSampleY = height - 1;\n      }\n      const activitySpan = Math.max(maxSampleX - minSampleX + 1, maxSampleY - minSampleY + 1);\n      const padding = Math.max(40, Math.ceil(activitySpan * 0.18));\n      minSampleX = Math.max(0, minSampleX - padding);\n      minSampleY = Math.max(0, minSampleY - padding);\n      maxSampleX = Math.min(width - 1, maxSampleX + padding);\n      maxSampleY = Math.min(height - 1, maxSampleY + padding);\n      const cropWidth = Math.max(1, maxSampleX - minSampleX + 1);\n      const cropHeight = Math.max(1, maxSampleY - minSampleY + 1);\n      const image = targetCtx.createImageData(cropWidth, cropHeight);\n      const isDistanceSlice = typeof mapPayload.unknown_value === 'number' || mapPayload.source === 'nvblox_distance_map_slice';\n      const unknownValue = Number(mapPayload.unknown_value);\n      for (let cropY = 0; cropY < cropHeight; cropY += 1) {\n        const srcY = minSampleY + cropY;\n        const srcRowOffset = srcY * width;\n        for (let cropX = 0; cropX < cropWidth; cropX += 1) {\n          const srcX = minSampleX + cropX;\n          const value = Number(data[srcRowOffset + srcX]);\n          const base = (cropY * cropWidth + cropX) * 4;\n          let r = 247; let g = 251; let b = 255; let a = 255;\n          if (isDistanceSlice) {\n            if (!Number.isFinite(value) || (Number.isFinite(unknownValue) && Math.abs(value - unknownValue) < 1e-3)) {\n              a = 0;\n            } else if (value <= 0.0) {\n              r = 73; g = 132; b = 196; a = 255;\n            } else {\n              r = 210; g = 233; b = 250; a = 235;\n            }\n          } else if (!Number.isFinite(value) || value < 0) {\n            a = 0;\n          } else if (value >= 65) {\n            r = 80; g = 144; b = 212; a = 255;\n          } else if (value <= 20) {\n            r = 206; g = 232; b = 250; a = 236;\n          } else {\n            const t = (value - 20) / 45;\n            r = Math.round(206 - (126 * t));\n            g = Math.round(232 - (88 * t));\n            b = Math.round(250 - (38 * t));\n            a = 246;\n          }\n          image.data[base] = r;\n          image.data[base + 1] = g;\n          image.data[base + 2] = b;\n          image.data[base + 3] = a;\n        }\n      }\n      const offscreen = document.createElement('canvas');\n      offscreen.width = cropWidth;\n      offscreen.height = cropHeight;\n      offscreen.getContext('2d').putImageData(image, 0, 0);\n      const scale = Math.min((targetCanvas.width * 0.88) / cropWidth, (targetCanvas.height * 0.88) / cropHeight);\n      const drawWidth = Math.max(1, Math.floor(cropWidth * scale));\n      const drawHeight = Math.max(1, Math.floor(cropHeight * scale));\n      const offsetX = Math.floor((targetCanvas.width - drawWidth) / 2);\n      const offsetY = Math.floor((targetCanvas.height - drawHeight) / 2);\n      targetCtx.save();\n      targetCtx.translate(offsetX, offsetY + drawHeight);\n      targetCtx.scale(1, -1);\n      targetCtx.imageSmoothingEnabled = false;\n      targetCtx.drawImage(offscreen, 0, 0, drawWidth, drawHeight);\n      targetCtx.restore();\n      targetCtx.save();\n      targetCtx.strokeStyle = 'rgba(103, 161, 219, 0.42)';\n      targetCtx.lineWidth = 1;\n      targetCtx.strokeRect(offsetX + 0.5, offsetY + 0.5, drawWidth - 1, drawHeight - 1);\n      targetCtx.restore();\n      return { offsetX, offsetY, drawWidth, drawHeight, sampleMinX: minSampleX, sampleMinY: minSampleY, sampleWidth: cropWidth, sampleHeight: cropHeight };\n    }\n\n    """


NEW_WORLD_TO_CANVAS_BLOCK = """function worldToCanvas(x, y) {\n      if (!latestMap || !lastDrawBounds) return null;\n      const sampleStride = Math.max(1, latestMap.sample_stride || 1);\n      const cellX = (x - latestMap.origin.x) / latestMap.resolution;\n      const cellY = (y - latestMap.origin.y) / latestMap.resolution;\n      const sampleX = cellX / sampleStride;\n      const sampleY = cellY / sampleStride;\n      const localSampleX = sampleX - (lastDrawBounds.sampleMinX || 0);\n      const localSampleY = sampleY - (lastDrawBounds.sampleMinY || 0);\n      if (localSampleX < 0 || localSampleY < 0 || localSampleX > lastDrawBounds.sampleWidth || localSampleY > lastDrawBounds.sampleHeight) return null;\n      return {\n        x: lastDrawBounds.offsetX + ((localSampleX + 0.5) / lastDrawBounds.sampleWidth) * lastDrawBounds.drawWidth,\n        y: lastDrawBounds.offsetY + lastDrawBounds.drawHeight - ((localSampleY + 0.5) / lastDrawBounds.sampleHeight) * lastDrawBounds.drawHeight,\n      };\n    }\n\n    """


NEW_CANVAS_TO_WORLD_BLOCK = """function canvasToWorld(clientX, clientY) {\n      if (!latestMap || !lastDrawBounds) return null;\n      const point = clientToCanvasPoint(clientX, clientY);\n      if (!point) return null;\n      const px = point.x;\n      const py = point.y;\n      const xInMap = (px - lastDrawBounds.offsetX) / lastDrawBounds.drawWidth;\n      const yInMap = 1 - ((py - lastDrawBounds.offsetY) / lastDrawBounds.drawHeight);\n      if (xInMap < 0 || xInMap > 1 || yInMap < 0 || yInMap > 1) return null;\n      const localSampleX = clamp(Math.floor(xInMap * lastDrawBounds.sampleWidth), 0, lastDrawBounds.sampleWidth - 1);\n      const localSampleY = clamp(Math.floor(yInMap * lastDrawBounds.sampleHeight), 0, lastDrawBounds.sampleHeight - 1);\n      const sampleX = localSampleX + (lastDrawBounds.sampleMinX || 0);\n      const sampleY = localSampleY + (lastDrawBounds.sampleMinY || 0);\n      const stride = Math.max(1, latestMap.sample_stride || 1);\n      const cellX = sampleX * stride + Math.floor(stride / 2);\n      const cellY = sampleY * stride + Math.floor(stride / 2);\n      return {\n        x: latestMap.origin.x + (cellX + 0.5) * latestMap.resolution,\n        y: latestMap.origin.y + (cellY + 0.5) * latestMap.resolution,\n        sampleX,\n        sampleY,\n      };\n    }\n\n    """


NEW_DRAW_MAP_BLOCK = """function drawMap() {\n      lastDrawBounds = drawOccupancyImage(canvas, ctx, latestMap, savedMode ? 'Waiting for saved 2D map...' : waitingLiveMapText);\n      if (!latestMap || !lastDrawBounds) return;\n      const showRuntimePose = navMode || savedMode || query.get('show_pose') === '1';\n      if (navMode) {\n        drawPolyline(latestGlobalPlan, '#d9534f', 2);\n        drawPolyline(latestLocalPlan, '#f0ad4e', 2);\n        drawPolygonOutline(latestLocalFootprint, '#ffd666', 2);\n      }\n      if (showRuntimePose && poseOnCurrentMap(latestDisplayPose)) {\n        const position = worldToCanvas(latestDisplayPose.x, latestDisplayPose.y);\n        if (position) {\n          drawMarker(position, '#45d7ff', 6, 2);\n          drawArrow(position, Number(latestDisplayPose.yaw || 0), '#45d7ff');\n        }\n      }\n      if (navMode && selectedTarget) {\n        const position = worldToCanvas(selectedTarget.x, selectedTarget.y);\n        if (position) {\n          drawMarker(position, '#ffb347', 8, 2);\n          drawArrow(position, Number(selectedTarget.yaw || 0), '#ffb347');\n        }\n      }\n      if (navMode && pendingAlignmentAnchor) {\n        const position = worldToCanvas(pendingAlignmentAnchor.x, pendingAlignmentAnchor.y);\n        if (position) drawMarker(position, '#6be8d0', 7, 2);\n      }\n      const initPose = navMode ? (selectedAlignmentPose || appliedAlignmentPose) : null;\n      if (initPose) {\n        const position = worldToCanvas(initPose.x, initPose.y);\n        if (position) {\n          drawMarker(position, '#1de9b6', 8, 2);\n          drawArrow(position, Number(initPose.yaw || 0), '#1de9b6');\n        }\n      }\n      pendingEdits.forEach((edit) => {\n        const worldX = latestMap.origin.x + (edit.cell_x + 0.5) * latestMap.resolution;\n        const worldY = latestMap.origin.y + (edit.cell_y + 0.5) * latestMap.resolution;\n        const position = worldToCanvas(worldX, worldY);\n        if (!position) return;\n        ctx.save();\n        ctx.fillStyle = edit.mode === 'erase' ? 'rgba(29,233,182,0.70)' : 'rgba(255,179,71,0.70)';\n        ctx.beginPath();\n        ctx.arc(position.x, position.y, 4, 0, Math.PI * 2);\n        ctx.fill();\n        ctx.restore();\n      });\n    }\n\n    """


OLD_TEMPORARY_VIEW_FEATURES_BLOCK = """    @contextmanager\n    def _temporary_view_features(\n        self,\n        feature_names: List[str],\n        *,\n        ttl: Optional[float] = None,\n        source: str = 'internal',\n    ):\n        effective_ttl = max(60.0, VIEW_LEASE_TTL_SEC * 6.0) if ttl is None else max(1.0, float(ttl))\n        lease = self.ros_state.activate_view_lease(feature_names, ttl=effective_ttl, source=source)\n        lease_id = str(lease.get('lease_id', '') or '').strip()\n        try:\n            yield\n        finally:\n            if lease_id:\n                self.ros_state.release_view_lease(lease_id)\n"""


