def replace_once(text: str, old: str, new: str, label: str) -> str:
    if old not in text:
        raise RuntimeError(f"patch target not found: {label}")
    return text.replace(old, new, 1)


def replace_if_present(text: str, old: str, new: str) -> str:
    if old in text:
        return text.replace(old, new)
    return text


def replace_between(text: str, start_marker: str, end_marker: str, new_block: str, label: str) -> str:
    start_index = text.find(start_marker)
    if start_index < 0:
        raise RuntimeError(f"patch target start not found: {label}")
    end_index = text.find(end_marker, start_index)
    if end_index < 0:
        raise RuntimeError(f"patch target end not found: {label}")
    return text[:start_index] + new_block + text[end_index:]


