def main() -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--dashboard-server", required=True)
    parser.add_argument("--index-html", required=True)
    parser.add_argument("--map2d-view-html", required=True)
    parser.add_argument("--lidar-view-html", required=True)
    args = parser.parse_args()

    patch_dashboard_server(Path(args.dashboard_server))
    patch_index_html(Path(args.index_html))
    patch_map2d_view(Path(args.map2d_view_html))
    patch_lidar_view_runtime(Path(args.lidar_view_html))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
